changeSet.sql:
CREATE TABLE nexus.catalog_documents ( tenant_id TEXT NOT NULL, tumbler TEXT NOT NULL, title TEXT NOT NULL, author TEXT, year INTEGER, content_type TEXT, file_path TEXT, corpus TEXT, physical_collection TEXT, chunk_count INTEGER, head_hash TEXT, indexed_at TEXT, metadata JSONB, source_mtime DOUBLE PRECISION NOT NULL DEFAULT 0, alias_of TEXT NOT NULL DEFAULT '', source_uri TEXT NOT NULL DEFAULT '', -- bibliographic enrichment (RDR-101 Phase 1) bib_year INTEGER NOT NULL DEFAULT 0, bib_authors TEXT NOT NULL DEFAULT '', bib_venue TEXT NOT NULL DEFAULT '', bib_citation_count INTEGER NOT NULL DEFAULT 0, bib_semantic_scholar_id TEXT NOT NULL DEFAULT '', bib_openalex_id TEXT NOT NULL DEFAULT '', bib_doi TEXT NOT NULL DEFAULT '', bib_enriched_at TEXT NOT NULL DEFAULT '', -- FTS tsvector: title=english (stemmed prose), author/corpus/file_path=simple (exact) -- OR'd query: plainto_tsquery('english',q) OR plainto_tsquery('simple',q) catches both fts_vector tsvector GENERATED ALWAYS AS ( to_tsvector('english', coalesce(title, '')) || to_tsvector('simple', coalesce(author, '')) || to_tsvector('simple', coalesce(corpus, '')) || to_tsvector('simple', coalesce(file_path, '')) ) STORED, CONSTRAINT catalog_documents_pk PRIMARY KEY (tenant_id, tumbler) );
-- GIN on fts_vector for sub-millisecond FTS queries CREATE INDEX idx_catalog_documents_fts ON nexus.catalog_documents USING GIN (fts_vector);
-- physical_collection lookup (list_by_collection, chashes_for_collection) CREATE INDEX idx_catalog_documents_collection ON nexus.catalog_documents (tenant_id, physical_collection);
-- source_uri lookup (by_source_uri, DT inverse join) - partial for non-empty URIs CREATE INDEX idx_catalog_documents_source_uri ON nexus.catalog_documents (tenant_id, source_uri) WHERE source_uri != '';
-- bib backend IDs (skip-check in nx enrich bib) CREATE INDEX idx_catalog_documents_bib_s2_id ON nexus.catalog_documents (tenant_id, bib_semantic_scholar_id) WHERE bib_semantic_scholar_id != '';
CREATE INDEX idx_catalog_documents_bib_oa_id ON nexus.catalog_documents (tenant_id, bib_openalex_id) WHERE bib_openalex_id != '';

CREATE TABLE nexus.catalog_links (
    tenant_id    TEXT    NOT NULL,
    id           BIGSERIAL,
    from_tumbler TEXT    NOT NULL,
    to_tumbler   TEXT    NOT NULL,
    link_type    TEXT    NOT NULL,
    from_span    TEXT,
    to_span      TEXT,
    created_by   TEXT    NOT NULL,
    created_at   TEXT,
    metadata     JSONB,
    CONSTRAINT catalog_links_pk PRIMARY KEY (tenant_id, id),
    -- uniqueness: one typed edge per (from, to) pair per tenant
    CONSTRAINT catalog_links_unique UNIQUE (tenant_id, from_tumbler, to_tumbler, link_type)
);

CREATE INDEX idx_catalog_links_from
    ON nexus.catalog_links (tenant_id, from_tumbler);

CREATE INDEX idx_catalog_links_to
    ON nexus.catalog_links (tenant_id, to_tumbler);

CREATE INDEX idx_catalog_links_type
    ON nexus.catalog_links (tenant_id, link_type);

CREATE INDEX idx_catalog_links_created_by
    ON nexus.catalog_links (tenant_id, created_by);

CREATE INDEX idx_catalog_links_from_type
    ON nexus.catalog_links (tenant_id, from_tumbler, link_type);

CREATE INDEX idx_catalog_links_to_type
    ON nexus.catalog_links (tenant_id, to_tumbler, link_type);

CREATE INDEX idx_catalog_links_created_by_type
    ON nexus.catalog_links (tenant_id, created_by, link_type);

CREATE TABLE nexus.catalog_document_chunks ( tenant_id TEXT NOT NULL, doc_id TEXT NOT NULL, position INTEGER NOT NULL, chash TEXT NOT NULL, chunk_index INTEGER, line_start INTEGER, line_end INTEGER, char_start INTEGER, char_end INTEGER, CONSTRAINT catalog_document_chunks_pk PRIMARY KEY (tenant_id, doc_id, position) );
-- chash lookup for reverse manifest traversal CREATE INDEX idx_catalog_chunks_chash ON nexus.catalog_document_chunks (tenant_id, chash);
-- doc_id lookup for purge/replace operations CREATE INDEX idx_catalog_chunks_doc_id ON nexus.catalog_document_chunks (tenant_id, doc_id);

CREATE TABLE nexus.catalog_collections ( tenant_id TEXT NOT NULL, name TEXT NOT NULL, content_type TEXT NOT NULL DEFAULT '', owner_id TEXT NOT NULL DEFAULT '', embedding_model TEXT NOT NULL DEFAULT '', model_version TEXT NOT NULL DEFAULT '', display_name TEXT NOT NULL DEFAULT '', legacy_grandfathered INTEGER NOT NULL DEFAULT 0, superseded_by TEXT NOT NULL DEFAULT '', superseded_at TEXT NOT NULL DEFAULT '', created_at TEXT NOT NULL DEFAULT '', CONSTRAINT catalog_collections_pk PRIMARY KEY (tenant_id, name) );
CREATE INDEX idx_catalog_collections_legacy ON nexus.catalog_collections (tenant_id, legacy_grandfathered);
CREATE INDEX idx_catalog_collections_owner ON nexus.catalog_collections (tenant_id, owner_id);
-- collection_for tuple lookup (RDR-103) CREATE INDEX idx_catalog_collections_tuple ON nexus.catalog_collections (tenant_id, content_type, owner_id, embedding_model);

CREATE TABLE nexus.catalog_meta (
    tenant_id TEXT NOT NULL,
    key       TEXT NOT NULL,
    value     TEXT,
    CONSTRAINT catalog_meta_pk PRIMARY KEY (tenant_id, key)
);

-- catalog_owners
ALTER TABLE nexus.catalog_owners ENABLE ROW LEVEL SECURITY;
ALTER TABLE nexus.catalog_owners FORCE ROW LEVEL SECURITY;
CREATE POLICY tenant_isolation ON nexus.catalog_owners
    USING      (tenant_id = current_setting('nexus.tenant', true))
    WITH CHECK (tenant_id = current_setting('nexus.tenant', true));

-- catalog_documents
ALTER TABLE nexus.catalog_documents ENABLE ROW LEVEL SECURITY;
ALTER TABLE nexus.catalog_documents FORCE ROW LEVEL SECURITY;
CREATE POLICY tenant_isolation ON nexus.catalog_documents
    USING      (tenant_id = current_setting('nexus.tenant', true))
    WITH CHECK (tenant_id = current_setting('nexus.tenant', true));

-- catalog_links
ALTER TABLE nexus.catalog_links ENABLE ROW LEVEL SECURITY;
ALTER TABLE nexus.catalog_links FORCE ROW LEVEL SECURITY;
CREATE POLICY tenant_isolation ON nexus.catalog_links
    USING      (tenant_id = current_setting('nexus.tenant', true))
    WITH CHECK (tenant_id = current_setting('nexus.tenant', true));

-- catalog_document_chunks
ALTER TABLE nexus.catalog_document_chunks ENABLE ROW LEVEL SECURITY;
ALTER TABLE nexus.catalog_document_chunks FORCE ROW LEVEL SECURITY;
CREATE POLICY tenant_isolation ON nexus.catalog_document_chunks
    USING      (tenant_id = current_setting('nexus.tenant', true))
    WITH CHECK (tenant_id = current_setting('nexus.tenant', true));

-- catalog_collections
ALTER TABLE nexus.catalog_collections ENABLE ROW LEVEL SECURITY;
ALTER TABLE nexus.catalog_collections FORCE ROW LEVEL SECURITY;
CREATE POLICY tenant_isolation ON nexus.catalog_collections
    USING      (tenant_id = current_setting('nexus.tenant', true))
    WITH CHECK (tenant_id = current_setting('nexus.tenant', true));

-- catalog_meta
ALTER TABLE nexus.catalog_meta ENABLE ROW LEVEL SECURITY;
ALTER TABLE nexus.catalog_meta FORCE ROW LEVEL SECURITY;
CREATE POLICY tenant_isolation ON nexus.catalog_meta
    USING      (tenant_id = current_setting('nexus.tenant', true))
    WITH CHECK (tenant_id = current_setting('nexus.tenant', true));

changeSet.rollback:
DROP POLICY IF EXISTS tenant_isolation ON nexus.catalog_meta;
ALTER TABLE nexus.catalog_meta NO FORCE ROW LEVEL SECURITY;
ALTER TABLE nexus.catalog_meta DISABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS tenant_isolation ON nexus.catalog_collections;
ALTER TABLE nexus.catalog_collections NO FORCE ROW LEVEL SECURITY;
ALTER TABLE nexus.catalog_collections DISABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS tenant_isolation ON nexus.catalog_document_chunks;
ALTER TABLE nexus.catalog_document_chunks NO FORCE ROW LEVEL SECURITY;
ALTER TABLE nexus.catalog_document_chunks DISABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS tenant_isolation ON nexus.catalog_links;
ALTER TABLE nexus.catalog_links NO FORCE ROW LEVEL SECURITY;
ALTER TABLE nexus.catalog_links DISABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS tenant_isolation ON nexus.catalog_documents;
ALTER TABLE nexus.catalog_documents NO FORCE ROW LEVEL SECURITY;
ALTER TABLE nexus.catalog_documents DISABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS tenant_isolation ON nexus.catalog_owners;
ALTER TABLE nexus.catalog_owners NO FORCE ROW LEVEL SECURITY;
ALTER TABLE nexus.catalog_owners DISABLE ROW LEVEL SECURITY;

changeSet.sql:
DO $$
BEGIN
    IF EXISTS (SELECT 1 FROM pg_roles WHERE rolname = 'nexus_svc') THEN
        EXECUTE 'GRANT SELECT, INSERT, UPDATE, DELETE ON nexus.catalog_owners TO nexus_svc';
        EXECUTE 'GRANT SELECT, INSERT, UPDATE, DELETE ON nexus.catalog_documents TO nexus_svc';
        EXECUTE 'GRANT SELECT, INSERT, UPDATE, DELETE ON nexus.catalog_links TO nexus_svc';
        EXECUTE 'GRANT SELECT, INSERT, UPDATE, DELETE ON nexus.catalog_document_chunks TO nexus_svc';
        EXECUTE 'GRANT SELECT, INSERT, UPDATE, DELETE ON nexus.catalog_collections TO nexus_svc';
        EXECUTE 'GRANT SELECT, INSERT, UPDATE, DELETE ON nexus.catalog_meta TO nexus_svc';
        EXECUTE 'GRANT USAGE ON SEQUENCE nexus.catalog_links_id_seq TO nexus_svc';
        RAISE NOTICE 'Granted catalog table privileges to nexus_svc';
    ELSE
        RAISE NOTICE 'nexus_svc role not found; skipping grants';
    END IF;
END
$$;
